-- Pickaxe Capital Archive schema extension
create table if not exists archive_imports (id uuid primary key default gen_random_uuid(), file_name text not null, total_links integer, unique_urls integer, folder_count integer, duplicate_count integer, local_file_count integer, status text default 'raw_imported', created_at timestamptz default now());
create table if not exists archive_folders (id uuid primary key default gen_random_uuid(), import_id uuid references archive_imports(id), parent_id uuid references archive_folders(id), name text not null, full_path text not null, depth integer, direct_link_count integer default 0, descendant_link_count integer default 0, likely_category text, owner_agent text, usefulness_score integer default 50, noise_score integer default 50, status text default 'watch', created_at timestamptz default now());
create table if not exists archive_sources (id uuid primary key default gen_random_uuid(), normalized_url text unique not null, original_url text not null, title text, domain text, category text, owner_agent text, trust_score integer default 50, usefulness_score integer default 50, noise_score integer default 50, freshness_score integer default 50, status text default 'watch', is_local_file boolean default false, created_at timestamptz default now(), updated_at timestamptz default now());
create table if not exists archive_source_locations (id uuid primary key default gen_random_uuid(), source_id uuid references archive_sources(id) on delete cascade, folder_id uuid references archive_folders(id) on delete cascade, folder_path text not null, title_at_location text, add_date text, created_at timestamptz default now());
create table if not exists archive_findings (id uuid primary key default gen_random_uuid(), source_id uuid references archive_sources(id), folder_id uuid references archive_folders(id), agent_name text not null, finding_type text not null, summary text not null, importance integer default 50, confidence integer default 50, suggested_action text, created_at timestamptz default now());
